def to_roman(n):
    if not isinstance(n, int) or not (1 <= n <= 3999):
        raise ValueError("Argument must be integer between 1 and 3999")

    val = [
        1000, 900, 500, 400,
        100, 90, 50, 40,
        10, 9, 5, 4,
        1
    ]
    syms = [
        "M", "CM", "D", "CD",
        "C", "XC", "L", "XL",
        "X", "IX", "V", "IV",
        "I"
    ]

    res = []
    for i in range(len(val)):
        while n >= val[i]:
            res.append(syms[i])
            n -= val[i]
    return ''.join(res)
